import java.util.ArrayList;
import java.util.List;

public class Solution {
    public static long[] solve(long[] nums) {
        int N = nums.length;
        if (N == 0) {
            return new long[0];
        }

        // L[i] stores the maximum value in nums[0...i-1]
        long[] L = new long[N];
        // R[i] stores the maximum value in nums[i+1...N-1]
        long[] R = new long[N];

        // --- Calculate L array (Left Maxima) ---
        // Since all nums[i] >= 1, initializing L[0] to 0 ensures the first element is considered greater than its (empty) left side.
        L[0] = 0;
        for (int i = 1; i < N; i++) {
            L[i] = Math.max(L[i-1], nums[i-1]);
        }

        // --- Calculate R array (Right Maxima) ---
        // Initializing R[N-1] to 0 ensures the last element is considered greater than its (empty) right side.
        R[N-1] = 0;
        for (int i = N - 2; i >= 0; i--) {
            R[i] = Math.max(R[i+1], nums[i+1]);
        }

        // --- Collect Effective Elements ---
        List<Long> resultList = new ArrayList<>();

        for (int i = 0; i < N; i++) {
            // An element is effective if it strictly exceeds the max of its left neighbors OR the max of its right neighbors.
            boolean strictlyGreaterLeft = nums[i] > L[i];
            boolean strictlyGreaterRight = nums[i] > R[i];

            if (strictlyGreaterLeft || strictlyGreaterRight) {
                resultList.add(nums[i]);
            }
        }

        // Convert List<Long> to long[]
        long[] result = new long[resultList.size()];
        for (int i = 0; i < resultList.size(); i++) {
            result[i] = resultList.get(i);
        }

        return result;
    }
}

